"""
Parameterized generator for GH751_quart_381.

Source PR:    https://github.com/pallets/quart/pull/381
Source Issue: N/A

Seed varies: renames 'action' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH751_quart_381'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH751_quart_381'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('action', 'action' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH751_quart_381',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'pallets/quart',
                "pr_number": 381,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/pallets/quart/pull/381",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            '.github/workflows/publish.yaml': 'name: Publish\non:\n  push:\n    tags:\n      - \'*\'\njobs:\n  build:\n    runs-on: ubuntu-latest\n    outputs:\n      hash: ${{ steps.hash.outputs.hash }}\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-python@v5\n        with:\n          python-version: \'3.x\'\n      - run: pip install poetry\n      - run: poetry build\n      # Generate hashes used for provenance.\n      - name: generate hash\n        id: hash\n        run: cd dist && echo "hash=$(sha256sum * | base64 -w0)" >> $GITHUB_OUTPUT\n      - uses: actions/upload-artifact@v4\n        with:\n          path: ./dist\n\n  provenance:\n    needs: [\'build\']\n    permissions:\n      actions: read\n      id-token: write\n      contents: write\n    # Can\'t pin with hash due to how this workflow works.\n    uses: slsa-framework/slsa-github-generator/.github/workflows/generator_generic_slsa3.yml@v1.10.0\n    with:\n      base64-subjects: ${{ needs.build.outputs.hash }}\n\n  create-release:\n    # Upload the sdist, wheels, and provenance to a GitHub release. They remain\n    # available as build artifacts for a while as well.\n    needs: [\'provenance\']\n    runs-on: ubuntu-latest\n    permissions:\n      contents: write\n    steps:\n      - uses: actions/download-artifact@v4\n      - name: create release\n        run: >\n          gh release create --draft --repo ${{ github.repository }}\n          ${{ github.ref_name }}\n          *.intoto.jsonl/* artifact/*\n        env:\n          GH_TOKEN: ${{ github.token }}\n  publish-pypi:\n    needs: [\'provenance\']\n    # Wait for approval before attempting to upload to PyPI. This allows reviewing the\n    # files in the draft release.\n    environment: \'publish\'\n    runs-on: ubuntu-latest\n    permissions:\n      id-token: write\n    steps:\n      - uses: actions/download-artifact@v4\n      # Try uploading to Test PyPI first, in case something fails.\n      - uses: pypa/gh-action-pypi-publish@release/v1\n        with:\n          repository-url: https://test.pypi.org/legacy/\n          packages-dir: artifact/\n      - uses: pypa/gh-action-pypi-publish@release/v1\n        with:\n          packages-dir: artifact/\n',
            'CHANGES.rst': '0.19.8 2024-10-25\n-----------------\n\n* Bugfix Fix missing check that caused the previous fix to raise an error. #366\n\n0.19.7 2024-10-25\n-----------------\n\n* Security Fix how ``max_form_memory_size`` is applied when parsing large\n  non-file fields. https://github.com/advisories/GHSA-q34m-jh98-gwm2\n\n0.19.6 2024-05-19\n-----------------\n\n* Bugfix use ContentRange in the right way. See issue #331.\n* Bugfix hold a strong reference to background tasks.\n* Bugfix avoid ResourceWarning in DataBody.__aiter__.\n\n0.19.5 2024-04-01\n-----------------\n\n* Bugfix DeprecationWarning from datetime.utcnow().\n* Bugfix ensure request files are closed.\n* Bugfix development restarting when commands are passed.\n* Restore teardown_websocket methods.\n* Correct the config_class type.\n* Allow kwargs to be passed to the test client (matches Flask API).\n\n0.19.4 2023-11-19\n-----------------\n\n* Bugfix program not closing on Ctrl+C in Windows.\n* Bugfix the typing for AfterWebsocket functions.\n* Improve the typing of the ensure_async method.\n* Add a shutdown event to the app.\n\n0.19.3 2023-10-04\n-----------------\n\n* Bugfix update the default config to better match Flask.\n\n0.19.2 2023-10-01\n-----------------\n\n* Bugfix restore the app {after, before}_websocket methods.\n* Bugfix correctly set the cli Group in Quart.\n\n0.19.1 2023-09-30\n-----------------\n\n* Bugfix remove QUART_ENV and env usage.\n\n0.19.0 2023-09-30\n-----------------\n\n* Remove Flask-Patch. It has been replaced with the Quart-Flask-Patch\n  extension.\n* Remove references to first request, as per Flask.\n* Await the background tasks before calling the after serving funcs.\n* Don\'t copy the app context into the background task.\n* Allow background tasks a grace period to complete during shutdown.\n* Base Quart on Flask, utilising Flask code where possible. This\n  introduces a dependency on Flask.\n* Bugfix trailing slash issue in URL concatenation for empty \'path\'\n* Bugfix Issue #219. Use only CR in SSE documentation.\n* Bugfix typing for websocket to accept auth data.\n* Bugfix ensure subdomains apply to nested blueprints.\n* Bugfix ensure make_response errors if the value is incorrect.\n* Bugfix propagated exception handling.\n* Bugfix ensure exceptions propagate before logging.\n* Bugfix cope with scope extension value being None.\n* Bugfix ensure the conditional 304 response is empty.\n* Bugfix handle empty path in URL concatenation.\n* Bugfix corrected typing hint for abort method at helpers.py.\n* Bugfix root_path usage.\n* Fix Werkzeug deprecation warnings.\n* Add svg\'s to jinja\'s autoescaping.\n* Improve the WebsocketResponse error, by including the response.\n* Add a file mode parameter to the config.from_file method.\n* Show the subdomain or host in the routes command output.\n* Upgrade to blinker 1.6.\n* Require Werkzeug 3.0.0 and Flask 3.0.0.\n* Use tomllib rather than toml.\n\n0.18.4 2023-04-09\n-----------------\n\n* Restrict blinker to < 1.6 for 0.18.x versions to ensure it works\n  with Quart\'s implementation.\n\n0.18.3 2022-10-08\n-----------------\n\n* Fixed Issue #206. Corrected quart.json.loads type annotation.\n* Bugfix signal handling on Windows.\n* Bugfix add missing globals to Flask-Patch.\n\n0.18.2 2022-10-04\n-----------------\n\n* Bugfix use add_signal_handler not signal.signal.\n\n0.18.1 2022-10-03\n-----------------\n\n* Bugfix static hosting with resource path escaping the root.\n* Bugfix adopt the Werkzeug/Flask make_conditional API/functionality.\n* Bugfix restore the reloader to Quart.\n* Bugfix support subdomains when testing.\n* Bugfix the signal handling to work on Windows.\n\n0.18.0 2022-07-23\n-----------------\n\n* Remove Quart\'s safe_join, use Werkzeug\'s version instead.\n* Drop toml dependency, as it isn\'t required in Quart (use\n  config.from_file as desired).\n* Change websocket.send_json to match jsonify\'s options.\n* Allow while serving decorators on blueprints.\n* Support synchronous background tasks, they will be run on a thread.\n* Follow Flask\'s API an allow empty argument Response construction.\n* Add get_root_path to helpers to match Flask.\n* Support silent argument in config.from_envvar.\n* Adopt Flask\'s logging setup.\n* Add stream_template and stream_template_string functions to stream a\n  large template in parts.\n* Switch to Flask\'s top level name exportion style.\n* Add aborter object to app to allow for abort customisation.\n* Add redirect method to app to allow for redirect customisation.\n* Remove usage of LocalStacks, using ContextVars more directly. This\n  should improve performance, but introduces backwards\n  incompatibility. _*_ctx_stack globals are removed, use *_context\n  instead. Extensions should store on ``g`` as appropriate. Requires\n  Werkzeug >= 2.2.0.\n* Returned lists are now jsonified.\n* Move url_for to the app to allow for url_for customisation.\n* Remove config from_json use from_file instead.\n* Match the Flask views classes and API.\n* Adopt the Flask cli code adding ``--app``, ``--env``, and ``-debug``\n  options to the CLI.\n* Adopt the Flask JSON provider interface, use instead of JSON\n  encoders and decoders.\n* Switch to being a Pallets project.\n* Requires at least v8 of click.\n\n\n0.17.0 2022-03-26\n-----------------\n\n* Raise startup and shutdown errors.\n* Allow loading of environment variables into the config.\n* Bugfix switch to Werkzeug\'s redirect.\n* Bugfix import Markup and escape from MarkupSafe.\n\n0.16.3 2022-02-02\n-----------------\n\n* Bugfix ensure auth is sent on test client requests.\n\n0.16.2 2021-12-14\n-----------------\n\n* Bugfix await background task shutdown after shutdown funcs.\n* Bugfix use the before websocket not request funcs.\n\n0.16.1 2021-11-17\n-----------------\n\n* Add missing serving exception handling.\n\n0.16.0 2021-11-09\n-----------------\n\n* Support an auth argument in the test client.\n* Support Python 3.10.\n* Utilise ensure_async in the copy context functions.\n* Add support for background tasks via ``app.add_background_task``.\n* Give a clearer error for invalid response types.\n* Make open_resource and open_instance_resource async.\n* Allow save_session to accept None as a response value.\n* Rename errors to have an ``Error`` suffix.\n* Bugfix typing of before (first) request callables.\n* Bugfix support view sync handlers.\n* Bugfix import of method "redirect" from flask.\n* Bugfix registering a blueprint twice with differing names.\n* Bugfix support ctx.pop() without passing exc explicitly.\n* Bugfix a request timeout error should be raised on timeout.\n* Bugfix remove jinja warnings.\n* Bugfix use the websocket context in the websocket method.\n* Bugfix raise any lifespan startup failures when testing.\n* Bugfix handler call order based on blueprint nesting.\n* Bugfix allow for generators that yield strings to be used.\n* Bugfix reorder acceptance to prevent race conditions.\n* Bugfix prevent multiple task form body parsing via a lock.\n\n0.15.1 2021-05-24\n-----------------\n\n* Improve the ``g`` AppGlobals typing.\n* Bugfix nested blueprint url_prefixes.\n* Bugfix ensure the session is created before url matching.\n* Bugfix Flask Patch sync wrapping async.\n* Bugfix don\'t try an parse the form data multiple times.\n* Bugfix blueprint naming allowing blueprints to be registered with a\n  different name.\n* Bugfix teardown callable typing.\n\n0.15.0 2021-05-11\n-----------------\n\n* Add the routes command, ``quart routes`` to output the routes in the\n  app.\n* Add the ability to close websocket connections with a reason if\n  supported by the server.\n* Revert AppContext lifespan interaction change in 0.14.0. It is not\n  possible to introduce this and match Flask\'s ``g`` usage.\n* Add syntatic sugar for route registration allowing ``app.get``,\n  ``app.post``, etc... for app and blueprint instances.\n* Support handlers returning a Werkzeug Response.\n* Remove Quart\'s exceptions and use Werkzeug\'s. This may cause\n  incompatibility to fix import from ``werkzeug.exceptions`` instead\n  of ``quart.exceptions``.\n* Switch to Werkzeug\'s locals and Sans-IO wrappers.\n* Allow for files to be sent via test client, via a ``files``\n  argument.\n* Make the NoAppException clearer.\n* Support nested blueprints.\n* Support while_serving functionality.\n* Bugfix Correct routing host case matching.\n* Bugfix cache flashed msg on request.flashes.\n* Bugfix debug defaults and overrides using run.\n* Bugfix adopt Werkzeug\'s timestamp parsing.\n* Bugfix only show the traceback response if propagating exceptions.\n* Bugfix unhandled exception handling.\n* Bugfix support url_for in websocket contexts.\n* Bugfix cookie jar handling in test client.\n* Bugfix support SERVER_NAME configuration for the run method.\n* Bugfix correctly support root_paths.\n* Bugfix support str and byte streamed responses.\n* Bugfix match Flask and consume the raw data when form parsing.\n\n0.14.1 2020-12-13\n-----------------\n\n* Bugfix add missing receive to test request connection and docs.\n* Bugfix Add the templates_auto_reload API.\n* Bugfix setting the debug property on the app now also sets the auto\n  reloading for the jinja environment.\n\n0.14.0 2020-12-05\n-----------------\n\n* Add user_agent property to requests/websockets - to easily extract\n  the user agent using Werkzeug\'s UserAgent class.\n* Bugfix set the content length when using send file - instead of\n  using chunked transfer encoding.\n* Introduce a test_app method - this should be used to ensure that\n  the startup & shutdown functions are run during testing.\n* Bugfix prevent local data sharing.\n* Officially support Python 3.9.\n* Add send and receive json to the test websocket client - allows a\n  simpler way for json to be sent and received using the app\'s encoder\n  and decoder.\n* Add signals for websocket message receipt and sending - specifically\n  the ``websocket_received`` and ``websocket_sent`` signals.\n* Add dump and load functions to the json module - as matching Flask.\n* Enhance the dev server output.\n* Change AppContext lifespan interaction - this pushes the app context\n  on startup and pops on shutdown meaning ``g`` is available\n  throughout without being cleared.\n* Major refactor of the testing system - this ensures that any\n  middleware and lifespans are correctly tested. It also introduces a\n  ``request`` method on the test client for a request connection (like\n  the websocket connection) for testing streaming.\n\n0.13.1 2020-09-09\n-----------------\n\n* Bugfix add the data property to the patched request attributes.\n* Bugfix WebSocket ASGI rejection (for servers that don\'t support the\n  ASGI WebSocket response extension).\n* Bugfix don\'t wrap commands in with_appcontext by default.\n* Bugfix CSP parsing for the report-only header.\n* Bugfix wait for tasks to complete when cancelled.\n* Bugfix clean up the generator when the response exits.\n* Bugfix request data handling with Flask-Patch.\n\n0.13.0 2020-07-14\n-----------------\n\n* Bugfix set cookies from the testing jar for websockets.\n* Restore Flask-Patch sync handling to pre 0.11. This means that sync\n  route handlers, before request, and more, are **not** run in a\n  thread if Flask-Patch is used. This restores Flask-SQLAlchemy\n  support (with Flask-Patch).\n* Bugfix accept additional attributes to the delete cookie.\n\n0.12.0 2020-05-21\n-----------------\n\n* Add certfile and keyfile arguments to cli.\n* Bugfix request host value returns an empty string rather than None\n  for HTTP/1.0 requests without a host header.\n* Bugfix type of query string argument to Werkzeug Map fixing a\n  TypeError.\n* Add ASGI scope dictionary to request.\n* Ensure that FlaskGroup exists when using flask_patch by patchin the\n  flask.cli module from quart.\n* Add quart.cli.with_appcontext matching the Flask API.\n* Make the quart.Blueprint registration api compatible with\n  flask.Blueprint.\n* Make the add_url_rule api match the flask API.\n* Resolve error handlers by most specific first (matches Flask).\n* Support test sessions and context preservation when testing.\n* Add lookup_app and lookup_request to flask patch globals.\n* Make quart.Blueprint API constructor fully compatible with\n  flask.Blueprint\n* Bugfix ensure (url) defaults aren\'t copied between blueprint routes.\n\n0.11.5 2020-03-31\n-----------------\n\n* Bugfix ensure any exceptions are raised in the ASGI handling code.\n* Bugfix support url defaults in the blueprint API.\n\n0.11.4 2020-03-29\n-----------------\n\n* Bugfix add a testing patch to ensure FlaskClient exists.\n* Security/Bugfix htmlsafe function.\n* Bugfix default to the map\'s strict slashes setting.\n* Bugfix host normalisation for route matching.\n* Bugfix add subdomain to the blueprint API.\n\n0.11.3 2020-02-26\n-----------------\n\n* Bugfix lowercase header names passed to cgi FieldStorage.\n\n0.11.2 2020-02-10\n-----------------\n\n* Bugfix debug traceback rendering.\n* Bugfix multipart/form-data parsing.\n* Bugfix uncomment cookie parameters.\n* Bugfix add await to the LocalProxy mappings.\n\n0.11.1 2020-02-09\n-----------------\n\n* Bugfix cors header accessors and setters.\n* Bugfix iscoroutinefunction with Python3.7.\n* Bugfix after request/websocket function typing.\n\n0.11.0 2020-02-08\n-----------------\n\n*This contains all the Bugfixes in the 0.6 branch.*\n\n* Allow relative root_path values.\n* Add a TooManyRequests, 429, exception.\n* Run synchronous code via a Thread Pool Executor. This means that\n  sync route handlers, before request, and more, are run in a\n  thread. **This is a major change.**\n* Add an asgi_app method for middleware usage, for example\n  ``quart_app.asgi_app = Middleware(quart_app.asgi_app)``.\n* Add a ``run_sync`` function to run synchronous code in a thread\n  pool with the Quart contexts present.\n* Bugfix set cookies on redirects when testing.\n* Bugfix follow the Flask API for dumps/loads.\n* Support loading configuration with a custom loader, ``from_file``\n  this allows for toml format configurations (among others).\n* Bugfix match the Werkzeug API in redirect.\n* Bugfix Respect QUART_DEBUG when using ``quart run``.\n* Follow the Flask exception propagation rules, ensuring exceptions\n  are propogated in testing.\n* Support Python 3.8.\n* Redirect with a 308 rather than 301 (following Flask/Werkzeug).\n* Add a _QUART_PATCHED marker to all patched modules.\n* Bugfix ensure multiple cookies are respected during testing.\n* Switch to Werkzeug for datastructures and header parsing and\n  dumping. **This is a major change.**\n* Make the lock class customisable by the app subclass, this allows\n  Quart-Trio to override the lock type.\n* Add a run_task method to Quart (app) class. This is a task based on\n  the run method assumptions that can be awaited or run as desired.\n* Switch JSON tag datetime format to allow reading of Flask encoded\n  tags.\n* Switch to Werkzeug\'s cookie code. **This is a major change.**\n* Switch to Werkzeug\'s routing code. **This is a major change.**\n* Add signal handling to run method, but not the run_task method.\n\n0.6.15 2019-10-17\n-----------------\n\n**This is the final 0.6 release and the final release to support Python3.6, Python3.8 is now available.**\n\n* Bugfix handle \'http.request\' without a \'body\' key\n\n0.10.0 2019-08-30\n-----------------\n\n*This contains all the Bugfixes in the 0.6 branch.*\n\n* Support aborting with a Response argument.\n* Fix JSON type hints to match typeshed.\n* Update to Hypercorn 0.7.0 as minimum version.\n* Bugfix ensure the default response timeout is set.\n* Allow returning dictionaries from view functions, this follows a new\n  addition to Flask.\n* Bugfix ensure the response timeout has a default.\n* Bugfix correct testing-websocket typing.\n* Accept json, data, or form arguments to test_request_context.\n* Support send_file sending a BytesIO object.\n* Add samesite cookie support (requires Python3.8).\n* Add a ContentSecurityPolicy datastructure, this follows a new\n  addition to Werkzeug.\n* Unblock logging I/O by logging in separate threads.\n* Support ASGI root_path as a prepended path to all routes.\n\n0.6.14 2019-08-30\n-----------------\n\n* Bugfix follow Werkzeug LocalProxy name API.\n* Bugfix ensure multiple files are correctly loaded.\n* Bugfix ensure make_response status code is an int.\n* Bugfix be clear about header encoding.\n* Bugfix ensure loading form/files data is timeout protected.\n* Bugfix add missing Unauthorized, Forbidden, and NotAcceptable\n  exception classes.\n\n0.9.1 2019-05-12\n----------------\n\n* Bugfix unquote the path in the test client, following the ASGI\n  standard.\n* Bugfix follow Werkzeug LocalProxy name API.\n* Bugfix ensure multiple files are correctly loaded.\n\n0.9.0 2019-04-22\n----------------\n\n*This contains all the Bugfixes in the 0.6 and 0.8 branches.*\n\n* Highlight the traceback line of code when using the debug system.\n* Bugfix ensure debug has an affect when passed to app run.\n* Change the test_request_context arguments to match the test client\n  open arguments.\n* Bugfix form data loading limit type.\n* Support async Session Interfaces (with continued support for sync\n  interfaces).\n* Added before_app_websocket, and after_app_websocket methods to the\n  Blueprint.\n* Support sending headers on WebSocket acceptance (this requires ASGI\n  server support, the default Hypercorn supports this).\n* Support async teardown functions (with continued support for sync\n  functions).\n* Match the Flask API argument order for send_file adding a mimetype\n  argument and supporting attachment sending.\n* Make the requested subprotocols available via the websocket class,\n  ``websocket.requested_subprotocols``.\n* Support session saving with WebSockets (errors for cookie sessions\n  if the WebSocket connection has been accepted).\n* Switch to be an ASGI 3 framework (this requires ASGI server support,\n  the default Hypercorn supports this).\n* Refactor push promise API, the removes the\n  ``response.push_promises`` attribute.\n* Aceept Path (types) throughout and switch to Path (types)\n  internally.\n\n0.6.13 2019-04-22\n-----------------\n\n* Bugfix multipart parsing.\n* Added Map.iter_rules(endpoint) Method.\n* Bugfix cope if there is no source code (when using the debug\n  system).\n\n0.8.1 2019-02-09\n----------------\n\n* Bugfix make the safe_join function stricter.\n* Bugfix parse multipart form data correctly.\n* Bugfix add missing await.\n\n0.8.0 2019-01-29\n----------------\n\n*This contains all the Bugfixes in the 0.6 and 0.7 branches.*\n\n* Bugfix raise an error if the loaded app is not a Quart instance.\n* Remove unused AccessLogAtoms\n* Change the Quart::run method interface, this reduces the available\n  options for simplicity. See hypercorn for an extended set of\n  deployment configuration.\n* Utilise the Hypercorn serve function, requires Hypercorn >= 0.5.0.\n* Added list_templates method to DispatchingJinjaLoader.\n* Add additional methods to the Accept datastructure, specifically\n  keyed accessors.\n* Expand the abort functionality and signature, to allow for the\n  description and name to be optionally specified.\n* Add a make_push_promise function, to allow for push promises to be\n  sent at any time during the request handling e.g. pre-emptive\n  pushes.\n* Rethink the Response Body structure to allow for more efficient\n  handling of file bodies and the ability to extend how files are\n  managed (for Quart-Trio and others).\n* Add the ability to send conditional 206 responses. Optionally a\n  response can be made conditional by awaiting the make_conditional\n  method with an argument of the request range.\n* Recommend Mangum for serverless deployments.\n* Added instance_path and instance_relative_config to allow for an\n  instance folder to be used.\n\n0.6.12 2019-01-29\n-----------------\n\n* Bugfix raise a BadRequest if the body encoding is wrong.\n* Limit Hypercorn to versions < 0.6.\n* Bugfix matching of MIMEAccept values.\n* Bugfix handle the special routing case of /.\n* Bugfix ensure sync functions work with async signals.\n* Bugfix ensure redirect location headers are full URLs.\n* Bugfix ensure open ended Range header works.\n* Bugfix ensure RequestEntityTooLarge errors are correctly raised.\n\n0.7.2 2019-01-03\n----------------\n\n* Fix the url display bug.\n* Avoid crash in flask_patch isinstance.\n* Cope with absolute paths sent in the scope.\n\n0.7.1 2018-12-18\n----------------\n\n* Bugfix Flask patching step definition.\n\n0.7.0 2018-12-16\n----------------\n\n* Support only Python 3.7, see the 0.6.X releases for continued Python\n  3.6 support.\n* Introduce ContextVars for local storage.\n* Change default redirect status code to 302.\n* Support integer/float cookie expires.\n* Specify cookie date format (differs to Flask).\n* Remove the Gunicorn workers, please use a ASGI server instead.\n* Remove Gunicorn compatibility.\n* Introduce a Headers data structure.\n* Implement follow_redirects in Quart test client.\n* Adopt the ASGI lifespan protocol.\n\n0.6.11 2018-12-09\n-----------------\n\n* Bugfix support static files in blueprints.\n* Bugfix ensure automatic options API matches Flask and works.\n* Bugfix app.run SSL usage and Hypercorn compatibility.\n\n0.6.10 2018-11-12\n-----------------\n\n* Bugfix async body iteration cleanup.\n\n0.6.9 2018-11-10\n----------------\n\n* Bugfix async body iteration deadlock.\n* Bufgix ASGI handling to ensure completion.\n\n0.6.8 2018-10-21\n----------------\n\n* Ensure an event loop is specified on app.run.\n* Bugfix ensure handler responses are finalized.\n* Bugfix ensure the ASGI callable returns on completion.\n\n0.6.7 2018-09-23\n----------------\n\n* Bugfix ASGI conversion of websocket data (str or bytes).\n* Bugfix ensure redirect url includes host when host matching.\n* Bugfix ensure query strings are present in redirect urls.\n* Bugfix ensure header values are string types.\n* Bugfix incorrect endpoint override error for synchronous view\n  functions.\n\n0.6.6 2018-08-27\n----------------\n\n* Bugfix add type conversion to getlist (on multidicts)\n* Bugfix correct ASGI client usage (allows for None)\n* Bugfix ensure overlapping requests work without destroying the\n  others context.\n* Bugfix ensure only integer status codes are accepted.\n\n0.6.5 2018-08-05\n----------------\n\n* Bugfix change default redirect status code to 302.\n* Bugfix support query string parsing from test client paths.\n* Bugfix support int/float cookie expires values.\n* Bugfix correct the cookie date format to RFC 822.\n* Bugfix copy sys.modules to prevent dictionary changed errors.\n* Bugfix ensure request body iteration returns all data.\n* Bugfix correct set host header (if missing) for HTTP/1.0.\n* Bugfix set the correct defaults for _external in url_for.\n\n0.6.4 2018-07-15\n----------------\n\n* Bugfix correctly handle request query strings.\n* Restore log output when running in development mode.\n* Bugfix allow for multiple query string values when building urls,\n  e.g. ``a=1&a=2``.\n* Bugfix ensure the Flask Patch system works with Python 3.7.\n\n0.6.3 2018-07-05\n----------------\n\n* Bugfix ensure compatibility with Python 3.7\n\n0.6.2 2018-06-24\n----------------\n\n* Bugfix remove class member patching from flask-patch system, as was\n  unreliable.\n* Bugfix ensure ASGI websocket handler closes on disconnect.\n* Bugfix cope with optional client values in ASGI scope.\n\n0.6.1 2018-06-18\n----------------\n\n* Bugfix accept PathLike objects to the ``send_file`` function.\n* Bugfix mutable methods in blueprint routes or url rule addition.\n* Bugfix don\'t lowercase header values.\n* Bugfix support automatic options on View classes.\n\n0.6.0 2018-06-11\n----------------\n\n* Quart is now an ASGI framework, and requires an ASGI server to serve\n  requests. `Hypercorn <https://gitlab.com/pgjones/hypercorn>`_ is\n  used in development and is recommended for production. Hypercorn\n  is a continuation of the Quart serving code.\n* Add before and after serving functionality, this is provisional.\n* Add caching, last modified and etag information to static files\n  served via send_file.\n* Bugfix date formatting in response headers.\n* Bugfix make_response should error if response is None.\n* Deprecate the Gunicorn workers, see ASGI servers (e.g. Uvicorn).\n* Bugfix ensure shell context processors work.\n* Change template context processors to be async, this is backwards\n  incompatible.\n* Change websocket API to be async, this is backwards incompatible.\n* Allow the websocket class to be configurable by users.\n* Bugfix catch signals on Windows.\n* Perserve context in Flask-Patch system.\n* Add the websocket API to blueprints.\n* Add host, subdomain, and default options to websocket routes.\n* Bugfix support defaults on route or add_url_rule usage.\n* Introduce a more useful BuildError\n* Bugfix match Flask after request function execution order.\n* Support ``required_methods`` on view functions.\n* Added CORS, Access Control, datastructures to request and response\n  objects.\n* Allow type conversion in (CI)MultiDict get.\n\n0.5.0 2018-04-13\n----------------\n\n* Further API compatibility with Flask, specifically submodules,\n  wrappers, and the app.\n* Bugfix ensure error handlers work.\n* Bugfix await get_data in Flask Patch system.\n* Bugfix rule building, specifically additional arguments as query\n  strings.\n* Ability to add defaults to routes on definition.\n* Bugfix allow set_cookie to accept bytes arguments.\n* Bugfix ensure mimetype are returned.\n* Add host matching, and subdomains for routes.\n* Introduce implicit sequence conversion to response data.\n* URL and host information on requests.\n* Add a debug page, which shows tracebacks on errors.\n* Bugfix accept header parsing.\n* Bugfix cope with multi lists in forms.\n* Add cache control, etag and range header structures.\n* Add host, url, scheme and path correctly to path wrappers.\n* Bugfix CLI module parsing.\n* Add auto reloading on file changes.\n* Bugfix ignore invalid upgrade headers.\n* Bugfix h2c requests when there is a body (to not upgrade).\n* Refactor of websocket API, matching the request API as an analogue.\n* Refactor to mitigate DOS attacks, add documentation section.\n* Allow event loop to be specified when running apps.\n* Bugfix ensure automatic options work.\n* Rename TestClient -> QuartClient to match Flask naming.\n\n0.4.1 2018-01-27\n----------------\n\n* Bugfix HTTP/2 support and pass h2spec compliance testing.\n* Bugifx Websocket support and pass autobahn fuzzy test compliance\n  testing.\n* Bugfix HEAD request support (don\'t try to send a body).\n* Bugfix content-type (remove forced override).\n\n0.4.0 2018-01-14\n----------------\n\n* Change to async signals and context management. This allows the\n  signal receivers to be async (which is much more useful) but\n  requires changes to any current usage (notably test contexts).\n* Add initial support of websockets.\n* Support HTTP/1.1 to HTTP/2 (h2c) upgrades, includes supporting\n  HTTP/2 without SSL (note browsers don\'t support this).\n* Add timing to access logging.\n* Add a new Logo :). Thanks to @koddr.\n* Support streaming of the request body.\n* Add initial CLI support, using click.\n* Add context copying helper functions and clarify how to stream a\n  response.\n* Improved tutorials.\n* Allow the request to be limited to prevent DOS attacks.\n\n0.3.1 2017-10-25\n----------------\n\n* Fix incorrect error message for HTTP/1.1 requests.\n* Fix HTTP/1.1 pipelining support and error handling.\n\n0.3.0 2017-10-10\n----------------\n\n* Change flask_ext name to flask_patch to clarify that it is not the\n  pre-existing flask_ext system and that it patches Quart to provide\n  Flask imports.\n* Added support for views.\n* Match Werkzeug API for FileStorage.\n* Support HTTP/2 pipelining.\n* Add access logging.\n* Add HTTP/2 Server push, see the ``push_promises`` Set on a Response\n  object.\n* Add idle timeouts.\n\n0.2.0 2017-07-22\n----------------\n\nThis is still an alpha version of Quart, some notable changes are,\n\n* Support for Flask extensions via the flask_ext module (if imported).\n* Initial documentation setup and actual documentation including API\n  docstrings.\n* Closer match to the Flask API, most modules now match the Flask\n  public API.\n\n0.1.0 2017-05-21\n----------------\n\n* Released initial pre alpha version.\n',
            'pyproject.toml': '[tool.poetry]\nname = "Quart"\nversion = "0.19.8"\ndescription = "A Python ASGI web microframework with the same API as Flask"\nauthors = ["pgjones <philip.graham.jones@googlemail.com>"]\nclassifiers = [\n    "Development Status :: 4 - Beta",\n    "Environment :: Web Environment",\n    "Intended Audience :: Developers",\n    "License :: OSI Approved :: MIT License",\n    "Operating System :: OS Independent",\n    "Programming Language :: Python",\n    "Programming Language :: Python :: 3",\n    "Programming Language :: Python :: 3.9",\n    "Programming Language :: Python :: 3.10",\n    "Programming Language :: Python :: 3.11",\n    "Programming Language :: Python :: 3.12",\n    "Programming Language :: Python :: 3.13",\n    "Topic :: Internet :: WWW/HTTP :: Dynamic Content",\n    "Topic :: Software Development :: Libraries :: Python Modules",\n]\ninclude = ["src/quart_auth/py.typed"]\nlicense = "MIT"\nreadme = "README.rst"\nrepository = "https://github.com/pallets/quart/"\ndocumentation = "https://quart.palletsprojects.com"\n\n[tool.poetry.dependencies]\npython = ">=3.9"\naiofiles = "*"\nblinker = ">=1.6"\nclick = ">=8.0.0"\nflask = ">=3.0.0"\nhypercorn = ">=0.11.2"\nimportlib_metadata = { version = "*", python = "<3.10" }\nitsdangerous = "*"\njinja2 = "*"\nmarkupsafe = "*"\npydata_sphinx_theme = { version = "*", optional = true }\npython-dotenv = { version = "*", optional = true }\ntyping_extensions = { version = "*", python = "<3.10" }\nwerkzeug = ">=3.0.0"\n\n[tool.poetry.dev-dependencies]\nhypothesis = "*"\npytest = "*"\npytest-asyncio = "*"\n\n[tool.poetry.scripts]\nquart = "quart.cli:main"\n\n[tool.poetry.extras]\ndocs = ["pydata_sphinx_theme"]\ndotenv = ["python-dotenv"]\n\n[tool.black]\nline-length = 100\ntarget-version = ["py39"]\n\n[tool.isort]\ncombine_as_imports = true\nforce_grid_wrap = 0\ninclude_trailing_comma = true\nknown_first_party = "quart, tests"\nline_length = 100\nmulti_line_output = 3\nno_lines_before = "LOCALFOLDER"\norder_by_type = false\nreverse_relative = true\n\n[tool.mypy]\nallow_redefinition = true\ndisallow_any_generics = false\ndisallow_subclassing_any = true\ndisallow_untyped_calls = false\ndisallow_untyped_defs = true\nimplicit_reexport = true\nno_implicit_optional = true\nshow_error_codes = true\nstrict = true\nstrict_equality = true\nstrict_optional = false\nwarn_redundant_casts = true\nwarn_return_any = false\nwarn_unused_configs = true\nwarn_unused_ignores = true\n\n[tool.pytest.ini_options]\naddopts = "--no-cov-on-fail --showlocals --strict-markers"\nasyncio_default_fixture_loop_scope = "session"\nasyncio_mode = "auto"\ntestpaths = ["tests"]\n\n[build-system]\nrequires = ["poetry-core>=1.0.0"]\nbuild-backend = "poetry.core.masonry.api"\n',
            'src/quart/app.py': 'from __future__ import annotations\n\nimport asyncio\nimport os\nimport signal\nimport sys\nimport warnings\nfrom collections import defaultdict\nfrom datetime import timedelta\nfrom inspect import isasyncgen, iscoroutinefunction as _inspect_iscoroutinefunction, isgenerator\nfrom types import TracebackType\nfrom typing import (\n    Any,\n    AnyStr,\n    AsyncGenerator,\n    Awaitable,\n    Callable,\n    cast,\n    Coroutine,\n    NoReturn,\n    Optional,\n    overload,\n    Set,\n    TypeVar,\n    Union,\n)\nfrom urllib.parse import quote\n\nfrom aiofiles import open as async_open\nfrom aiofiles.base import AiofilesContextManager\nfrom flask.sansio.app import App\nfrom flask.sansio.scaffold import setupmethod\nfrom hypercorn.asyncio import serve\nfrom hypercorn.config import Config as HyperConfig\nfrom hypercorn.typing import ASGIReceiveCallable, ASGISendCallable, Scope\nfrom werkzeug.datastructures import Authorization, Headers, ImmutableDict\nfrom werkzeug.exceptions import Aborter, BadRequestKeyError, HTTPException, InternalServerError\nfrom werkzeug.routing import BuildError, MapAdapter, RoutingException\nfrom werkzeug.wrappers import Response as WerkzeugResponse\n\nfrom .asgi import ASGIHTTPConnection, ASGILifespan, ASGIWebsocketConnection\nfrom .cli import AppGroup\nfrom .config import Config\nfrom .ctx import (\n    _AppCtxGlobals,\n    AppContext,\n    has_request_context,\n    has_websocket_context,\n    RequestContext,\n    WebsocketContext,\n)\nfrom .globals import (\n    _cv_app,\n    _cv_request,\n    _cv_websocket,\n    g,\n    request,\n    request_ctx,\n    session,\n    websocket,\n    websocket_ctx,\n)\nfrom .helpers import get_debug_flag, get_flashed_messages, send_from_directory\nfrom .routing import QuartMap, QuartRule\nfrom .sessions import SecureCookieSessionInterface\nfrom .signals import (\n    appcontext_tearing_down,\n    got_background_exception,\n    got_request_exception,\n    got_serving_exception,\n    got_websocket_exception,\n    request_finished,\n    request_started,\n    request_tearing_down,\n    websocket_finished,\n    websocket_started,\n    websocket_tearing_down,\n)\nfrom .templating import _default_template_ctx_processor, Environment\nfrom .testing import (\n    make_test_body_with_headers,\n    make_test_headers_path_and_query_string,\n    make_test_scope,\n    no_op_push,\n    QuartClient,\n    QuartCliRunner,\n    sentinel,\n    TestApp,\n)\nfrom .typing import (\n    AfterServingCallable,\n    AfterWebsocketCallable,\n    ASGIHTTPProtocol,\n    ASGILifespanProtocol,\n    ASGIWebsocketProtocol,\n    BeforeServingCallable,\n    BeforeWebsocketCallable,\n    Event,\n    FilePath,\n    HeadersValue,\n    ResponseReturnValue,\n    ResponseTypes,\n    ShellContextProcessorCallable,\n    StatusCode,\n    TeardownCallable,\n    TemplateFilterCallable,\n    TemplateGlobalCallable,\n    TemplateTestCallable,\n    TestAppProtocol,\n    TestClientProtocol,\n    WebsocketCallable,\n    WhileServingCallable,\n)\nfrom .utils import (\n    cancel_tasks,\n    file_path_to_path,\n    MustReloadError,\n    observe_changes,\n    restart,\n    run_sync,\n)\nfrom .wrappers import BaseRequestWebsocket, Request, Response, Websocket\n\ntry:\n    from typing import ParamSpec\nexcept ImportError:\n    from typing_extensions import ParamSpec\n\n# Python 3.14 deprecated asyncio.iscoroutinefunction, but suggested\n# inspect.iscoroutinefunction does not work correctly in some Python\n# versions before 3.12.\n# See https://github.com/python/cpython/issues/122858#issuecomment-2466239748\nif sys.version_info >= (3, 12):\n    iscoroutinefunction = _inspect_iscoroutinefunction\nelse:\n    iscoroutinefunction = asyncio.iscoroutinefunction\n\nAppOrBlueprintKey = Optional[str]  # The App key is None, whereas blueprints are named\nT_after_serving = TypeVar("T_after_serving", bound=AfterServingCallable)\nT_after_websocket = TypeVar("T_after_websocket", bound=AfterWebsocketCallable)\nT_before_serving = TypeVar("T_before_serving", bound=BeforeServingCallable)\nT_before_websocket = TypeVar("T_before_websocket", bound=BeforeWebsocketCallable)\nT_shell_context_processor = TypeVar(\n    "T_shell_context_processor", bound=ShellContextProcessorCallable\n)\nT_teardown = TypeVar("T_teardown", bound=TeardownCallable)\nT_template_filter = TypeVar("T_template_filter", bound=TemplateFilterCallable)\nT_template_global = TypeVar("T_template_global", bound=TemplateGlobalCallable)\nT_template_test = TypeVar("T_template_test", bound=TemplateTestCallable)\nT_websocket = TypeVar("T_websocket", bound=WebsocketCallable)\nT_while_serving = TypeVar("T_while_serving", bound=WhileServingCallable)\n\nT = TypeVar("T")\nP = ParamSpec("P")\n\n\ndef _make_timedelta(value: timedelta | int | None) -> timedelta | None:\n    if value is None or isinstance(value, timedelta):\n        return value\n\n    return timedelta(seconds=value)\n\n\nclass Quart(App):\n    """The web framework class, handles requests and returns responses.\n\n    The primary method from a serving viewpoint is\n    :meth:`~quart.app.Quart.handle_request`, from an application\n    viewpoint all the other methods are vital.\n\n    This can be extended in many ways, with most methods designed with\n    this in mind. Additionally any of the classes listed as attributes\n    can be replaced.\n\n    Attributes:\n        aborter_class: The class to use to raise HTTP error via the abort\n            helper function.\n        app_ctx_globals_class: The class to use for the ``g`` object\n        asgi_http_class: The class to use to handle the ASGI HTTP\n            protocol.\n        asgi_lifespan_class: The class to use to handle the ASGI\n            lifespan protocol.\n        asgi_websocket_class: The class to use to handle the ASGI\n            websocket protocol.\n        config_class: The class to use for the configuration.\n        env: The name of the environment the app is running on.\n        event_class: The class to use to signal an event in an async\n            manner.\n        debug: Wrapper around configuration DEBUG value, in many places\n            this will result in more output if True. If unset, debug\n            mode will be activated if environ is set to \'development\'.\n        jinja_environment: The class to use for the jinja environment.\n        jinja_options: The default options to set when creating the jinja\n            environment.\n        permanent_session_lifetime: Wrapper around configuration\n            PERMANENT_SESSION_LIFETIME value. Specifies how long the session\n            data should survive.\n        request_class: The class to use for requests.\n        response_class: The class to user for responses.\n        secret_key: Warpper around configuration SECRET_KEY value. The app\n            secret for signing sessions.\n        session_interface: The class to use as the session interface.\n        shutdown_event: This event is set when the app starts to\n            shutdown allowing waiting tasks to know when to stop.\n        url_map_class: The class to map rules to endpoints.\n        url_rule_class: The class to use for URL rules.\n        websocket_class: The class to use for websockets.\n\n    """\n\n    asgi_http_class: type[ASGIHTTPProtocol]\n    asgi_lifespan_class: type[ASGILifespanProtocol]\n    asgi_websocket_class: type[ASGIWebsocketProtocol]\n    shutdown_event: Event\n    test_app_class: type[TestAppProtocol]\n    test_client_class: type[TestClientProtocol]  # type: ignore[assignment]\n\n    aborter_class = Aborter\n    app_ctx_globals_class = _AppCtxGlobals\n    asgi_http_class = ASGIHTTPConnection\n    asgi_lifespan_class = ASGILifespan\n    asgi_websocket_class = ASGIWebsocketConnection\n    config_class = Config\n    event_class = asyncio.Event\n    jinja_environment = Environment  # type: ignore[assignment]\n    lock_class = asyncio.Lock\n    request_class = Request\n    response_class = Response\n    session_interface = SecureCookieSessionInterface()\n    test_app_class = TestApp\n    test_client_class = QuartClient  # type: ignore[assignment]\n    test_cli_runner_class = QuartCliRunner  # type: ignore\n    url_map_class = QuartMap\n    url_rule_class = QuartRule  # type: ignore[assignment]\n    websocket_class = Websocket\n\n    default_config = ImmutableDict(\n        {\n            "APPLICATION_ROOT": "/",\n            "BACKGROUND_TASK_SHUTDOWN_TIMEOUT": 5,  # Second\n            "BODY_TIMEOUT": 60,  # Second\n            "DEBUG": None,\n            "ENV": None,\n            "EXPLAIN_TEMPLATE_LOADING": False,\n            "MAX_CONTENT_LENGTH": 16 * 1024 * 1024,  # 16 MB Limit\n            "MAX_COOKIE_SIZE": 4093,\n            "PERMANENT_SESSION_LIFETIME": timedelta(days=31),\n            # Replaces PREFERRED_URL_SCHEME to allow for WebSocket scheme\n            "PREFER_SECURE_URLS": False,\n            "PRESERVE_CONTEXT_ON_EXCEPTION": None,\n            "PROPAGATE_EXCEPTIONS": None,\n            "PROVIDE_AUTOMATIC_OPTIONS": True,\n            "RESPONSE_TIMEOUT": 60,  # Second\n            "SECRET_KEY": None,\n            "SEND_FILE_MAX_AGE_DEFAULT": timedelta(hours=12),\n            "SERVER_NAME": None,\n            "SESSION_COOKIE_DOMAIN": None,\n            "SESSION_COOKIE_HTTPONLY": True,\n            "SESSION_COOKIE_NAME": "session",\n            "SESSION_COOKIE_PATH": None,\n            "SESSION_COOKIE_SAMESITE": None,\n            "SESSION_COOKIE_SECURE": False,\n            "SESSION_REFRESH_EACH_REQUEST": True,\n            "TEMPLATES_AUTO_RELOAD": None,\n            "TESTING": False,\n            "TRAP_BAD_REQUEST_ERRORS": None,\n            "TRAP_HTTP_EXCEPTIONS": False,\n        }\n    )\n\n    def __init__(\n        self,\n        import_name: str,\n        static_url_path: str | None = None,\n        static_folder: str | None = "static",\n        static_host: str | None = None,\n        host_matching: bool = False,\n        subdomain_matching: bool = False,\n        template_folder: str | None = "templates",\n        instance_path: str | None = None,\n        instance_relative_config: bool = False,\n        root_path: str | None = None,\n    ) -> None:\n        """Construct a Quart web application.\n\n        Use to create a new web application to which requests should\n        be handled, as specified by the various attached url\n        rules. See also :class:`~quart.static.PackageStatic` for\n        additional constructor arguments.\n\n        Arguments:\n            import_name: The name at import of the application, use\n                ``__name__`` unless there is a specific issue.\n            host_matching: Optionally choose to match the host to the\n                configured host on request (404 if no match).\n            instance_path: Optional path to an instance folder, for\n                deployment specific settings and files.\n            instance_relative_config: If True load the config from a\n                path relative to the instance path.\n        Attributes:\n            after_request_funcs: The functions to execute after a\n                request has been handled.\n            after_websocket_funcs: The functions to execute after a\n                websocket has been handled.\n            before_request_funcs: The functions to execute before handling\n                a request.\n            before_websocket_funcs: The functions to execute before handling\n                a websocket.\n        """\n        super().__init__(\n            import_name,\n            static_url_path,\n            static_folder,\n            static_host,\n            host_matching,\n            subdomain_matching,\n            template_folder,\n            instance_path,\n            instance_relative_config,\n            root_path,\n        )\n\n        self.after_serving_funcs: list[Callable[[], Awaitable[None]]] = []\n        self.after_websocket_funcs: dict[AppOrBlueprintKey, list[AfterWebsocketCallable]] = (\n            defaultdict(list)\n        )\n        self.background_tasks: Set[asyncio.Task] = set()\n        self.before_serving_funcs: list[Callable[[], Awaitable[None]]] = []\n        self.before_websocket_funcs: dict[AppOrBlueprintKey, list[BeforeWebsocketCallable]] = (\n            defaultdict(list)\n        )\n        self.teardown_websocket_funcs: dict[AppOrBlueprintKey, list[TeardownCallable]] = (\n            defaultdict(list)\n        )\n        self.while_serving_gens: list[AsyncGenerator[None, None]] = []\n\n        self.template_context_processors[None] = [_default_template_ctx_processor]\n\n        self.cli = AppGroup()\n        self.cli.name = self.name\n\n        if self.has_static_folder:\n            assert (\n                bool(static_host) == host_matching\n            ), "Invalid static_host/host_matching combination"\n\n            self.add_url_rule(\n                f"{self.static_url_path}/<path:filename>",\n                "static",\n                self.send_static_file,\n                host=static_host,\n            )\n\n    def get_send_file_max_age(self, filename: str | None) -> int | None:\n        """Used by :func:`send_file` to determine the ``max_age`` cache\n        value for a given file path if it wasn\'t passed.\n\n        By default, this returns :data:`SEND_FILE_MAX_AGE_DEFAULT` from\n        the configuration of :data:`~flask.current_app`. This defaults\n        to ``None``, which tells the browser to use conditional requests\n        instead of a timed cache, which is usually preferable.\n\n        Note this is a duplicate of the same method in the Quart\n        class.\n\n        """\n        value = self.config["SEND_FILE_MAX_AGE_DEFAULT"]\n\n        if value is None:\n            return None\n\n        if isinstance(value, timedelta):\n            return int(value.total_seconds())\n\n        return value\n        return None\n\n    async def send_static_file(self, filename: str) -> Response:\n        if not self.has_static_folder:\n            raise RuntimeError("No static folder for this object")\n        return await send_from_directory(self.static_folder, filename)\n\n    async def open_resource(\n        self,\n        path: FilePath,\n        mode: str = "rb",\n    ) -> AiofilesContextManager:\n        """Open a file for reading.\n\n        Use as\n\n        .. code-block:: python\n\n            async with await app.open_resource(path) as file_:\n                await file_.read()\n        """\n        if mode not in {"r", "rb", "rt"}:\n            raise ValueError("Files can only be opened for reading")\n\n        return async_open(os.path.join(self.root_path, path), mode)  # type: ignore\n\n    async def open_instance_resource(\n        self, path: FilePath, mode: str = "rb"\n    ) -> AiofilesContextManager:\n        """Open a file for reading.\n\n        Use as\n\n        .. code-block:: python\n\n            async with await app.open_instance_resource(path) as file_:\n                await file_.read()\n        """\n        return async_open(self.instance_path / file_path_to_path(path), mode)  # type: ignore\n\n    def create_jinja_environment(self) -> Environment:  # type: ignore\n        """Create and return the jinja environment.\n\n        This will create the environment based on the\n        :attr:`jinja_options` and configuration settings. The\n        environment will include the Quart globals by default.\n        """\n        options = dict(self.jinja_options)\n        if "autoescape" not in options:\n            options["autoescape"] = self.select_jinja_autoescape\n        if "auto_reload" not in options:\n            options["auto_reload"] = self.config["TEMPLATES_AUTO_RELOAD"]\n        jinja_env = self.jinja_environment(self, **options)  # type: ignore\n        jinja_env.globals.update(\n            {\n                "config": self.config,\n                "g": g,\n                "get_flashed_messages": get_flashed_messages,\n                "request": request,\n                "session": session,\n                "url_for": self.url_for,\n            }\n        )\n        jinja_env.policies["json.dumps_function"] = self.json.dumps\n        return jinja_env\n\n    async def update_template_context(self, context: dict) -> None:\n        """Update the provided template context.\n\n        This adds additional context from the various template context\n        processors.\n\n        Arguments:\n            context: The context to update (mutate).\n        """\n        names = [None]\n        if has_request_context():\n            names.extend(reversed(request_ctx.request.blueprints))  # type: ignore\n        elif has_websocket_context():\n            names.extend(reversed(websocket_ctx.websocket.blueprints))  # type: ignore\n\n        extra_context: dict = {}\n        for name in names:\n            for processor in self.template_context_processors[name]:\n                extra_context.update(await self.ensure_async(processor)())  # type: ignore\n\n        original = context.copy()\n        context.update(extra_context)\n        context.update(original)\n\n    @setupmethod\n    def before_serving(\n        self,\n        func: T_before_serving,\n    ) -> T_before_serving:\n        """Add a before serving function.\n\n        This will allow the function provided to be called once before\n        anything is served (before any byte is received).\n\n        This is designed to be used as a decorator, if used to\n        decorate a synchronous function, the function will be wrapped\n        in :func:`~quart.utils.run_sync` and run in a thread executor\n        (with the wrapped function returned). An example usage,\n\n        .. code-block:: python\n\n            @app.before_serving\n            async def func():\n                ...\n\n        Arguments:\n            func: The function itself.\n        """\n        self.before_serving_funcs.append(func)\n        return func\n\n    @setupmethod\n    def while_serving(\n        self,\n        func: T_while_serving,\n    ) -> T_while_serving:\n        """Add a while serving generator function.\n\n        This will allow the generator provided to be invoked at\n        startup and then again at shutdown.\n\n        This is designed to be used as a decorator. An example usage,\n\n        .. code-block:: python\n\n            @app.while_serving\n            async def func():\n                ...  # Startup\n                yield\n                ...  # Shutdown\n\n        Arguments:\n            func: The function itself.\n\n        """\n        self.while_serving_gens.append(func())\n        return func\n\n    @setupmethod\n    def after_serving(\n        self,\n        func: T_after_serving,\n    ) -> T_after_serving:\n        """Add a after serving function.\n\n        This will allow the function provided to be called once after\n        anything is served (after last byte is sent).\n\n        This is designed to be used as a decorator, if used to\n        decorate a synchronous function, the function will be wrapped\n        in :func:`~quart.utils.run_sync` and run in a thread executor\n        (with the wrapped function returned). An example usage,\n\n        .. code-block:: python\n\n            @app.after_serving\n            async def func():\n                ...\n\n        Arguments:\n            func: The function itself.\n        """\n        self.after_serving_funcs.append(func)\n        return func\n\n    def create_url_adapter(self, request: BaseRequestWebsocket | None) -> MapAdapter | None:\n        """Create and return a URL adapter.\n\n        This will create the adapter based on the request if present\n        otherwise the app configuration.\n        """\n        if request is not None:\n            subdomain = (\n                (self.url_map.default_subdomain or None) if not self.subdomain_matching else None\n            )\n\n            return self.url_map.bind_to_request(  # type: ignore[attr-defined]\n                request, subdomain, self.config["SERVER_NAME"]\n            )\n\n        if self.config["SERVER_NAME"] is not None:\n            scheme = "https" if self.config["PREFER_SECURE_URLS"] else "http"\n            return self.url_map.bind(self.config["SERVER_NAME"], url_scheme=scheme)\n        return None\n\n    def websocket(\n        self,\n        rule: str,\n        **options: Any,\n    ) -> Callable[[T_websocket], T_websocket]:\n        """Add a websocket to the application.\n\n        This is designed to be used as a decorator, if used to\n        decorate a synchronous function, the function will be wrapped\n        in :func:`~quart.utils.run_sync` and run in a thread executor\n        (with the wrapped function returned). An example usage,\n\n        .. code-block:: python\n\n            @app.websocket(\'/\')\n            async def websocket_route():\n                ...\n\n        Arguments:\n            rule: The path to route on, should start with a ``/``.\n            endpoint: Optional endpoint name, if not present the\n                function name is used.\n            defaults: A dictionary of variables to provide automatically, use\n                to provide a simpler default path for a route, e.g. to allow\n                for ``/book`` rather than ``/book/0``,\n\n                .. code-block:: python\n\n                    @app.websocket(\'/book\', defaults={\'page\': 0})\n                    @app.websocket(\'/book/<int:page>\')\n                    def book(page):\n                        ...\n\n            host: The full host name for this route (should include subdomain\n                if needed) - cannot be used with subdomain.\n            subdomain: A subdomain for this specific route.\n            strict_slashes: Strictly match the trailing slash present in the\n                path. Will redirect a leaf (no slash) to a branch (with slash).\n        """\n\n        def decorator(func: T_websocket) -> T_websocket:\n            endpoint = options.pop("endpoint", None)\n            self.add_websocket(\n                rule,\n                endpoint,\n                func,\n                **options,\n            )\n            return func\n\n        return decorator\n\n    def add_websocket(\n        self,\n        rule: str,\n        endpoint: str | None = None,\n        view_func: WebsocketCallable | None = None,\n        **options: Any,\n    ) -> None:\n        """Add a websocket url rule to the application.\n\n        This is designed to be used on the application directly. An\n        example usage,\n\n        .. code-block:: python\n\n            def websocket_route():\n                ...\n\n            app.add_websocket(\'/\', websocket_route)\n\n        Arguments:\n            rule: The path to route on, should start with a ``/``.\n            endpoint: Optional endpoint name, if not present the\n                function name is used.\n            view_func: Callable that returns a response.\n            defaults: A dictionary of variables to provide automatically, use\n                to provide a simpler default path for a route, e.g. to allow\n                for ``/book`` rather than ``/book/0``,\n\n                .. code-block:: python\n\n                    @app.websocket(\'/book\', defaults={\'page\': 0})\n                    @app.websocket(\'/book/<int:page>\')\n                    def book(page):\n                        ...\n\n            host: The full host name for this route (should include subdomain\n                if needed) - cannot be used with subdomain.\n            subdomain: A subdomain for this specific route.\n            strict_slashes: Strictly match the trailing slash present in the\n                path. Will redirect a leaf (no slash) to a branch (with slash).\n        """\n        return self.add_url_rule(\n            rule,\n            endpoint,\n            view_func,\n            methods={"GET"},\n            websocket=True,\n            **options,\n        )\n\n    def url_for(\n        self,\n        endpoint: str,\n        *,\n        _anchor: str | None = None,\n        _external: bool | None = None,\n        _method: str | None = None,\n        _scheme: str | None = None,\n        **values: Any,\n    ) -> str:\n        """Return the url for a specific endpoint.\n\n        This is most useful in templates and redirects to create a URL\n        that can be used in the browser.\n\n        Arguments:\n            endpoint: The endpoint to build a url for, if prefixed with\n                ``.`` it targets endpoint\'s in the current blueprint.\n            _anchor: Additional anchor text to append (i.e. #text).\n            _external: Return an absolute url for external (to app) usage.\n            _method: The method to consider alongside the endpoint.\n            _scheme: A specific scheme to use.\n            values: The values to build into the URL, as specified in\n                the endpoint rule.\n        """\n\n        app_context = _cv_app.get(None)\n        request_context = _cv_request.get(None)\n        websocket_context = _cv_websocket.get(None)\n\n        if request_context is not None:\n            url_adapter = request_context.url_adapter\n            if endpoint.startswith("."):\n                if request.blueprint is not None:\n                    endpoint = request.blueprint + endpoint\n                else:\n                    endpoint = endpoint[1:]\n            if _external is None:\n                _external = _scheme is not None\n        elif websocket_context is not None:\n            url_adapter = websocket_context.url_adapter\n            if endpoint.startswith("."):\n                if websocket.blueprint is not None:\n                    endpoint = websocket.blueprint + endpoint\n                else:\n                    endpoint = endpoint[1:]\n            if _external is None:\n                _external = _scheme is not None\n        elif app_context is not None:\n            url_adapter = app_context.url_adapter\n            if _external is None:\n                _external = True\n        else:\n            url_adapter = self.create_url_adapter(None)\n            if _external is None:\n                _external = True\n\n        if url_adapter is None:\n            raise RuntimeError(\n                "Unable to create a url adapter, try setting the SERVER_NAME config variable."\n            )\n        if _scheme is not None and not _external:\n            raise ValueError("External must be True for scheme usage")\n\n        self.inject_url_defaults(endpoint, values)\n\n        old_scheme = None\n        if _scheme is not None:\n            old_scheme = url_adapter.url_scheme\n            url_adapter.url_scheme = _scheme\n\n        try:\n            url = url_adapter.build(endpoint, values, method=_method, force_external=_external)\n        except BuildError as error:\n            return self.handle_url_build_error(error, endpoint, values)\n        finally:\n            if old_scheme is not None:\n                url_adapter.url_scheme = old_scheme\n\n        if _anchor is not None:\n            quoted_anchor = quote(_anchor, safe="%!#$&\'()*+,/:;=?@")\n            url = f"{url}#{quoted_anchor}"\n        return url\n\n    def make_shell_context(self) -> dict:\n        """Create a context for interactive shell usage.\n\n        The :attr:`shell_context_processors` can be used to add\n        additional context.\n        """\n        context = {"app": self, "g": g}\n        for processor in self.shell_context_processors:\n            context.update(processor())\n        return context\n\n    def run(\n        self,\n        host: str | None = None,\n        port: int | None = None,\n        debug: bool | None = None,\n        use_reloader: bool = True,\n        loop: asyncio.AbstractEventLoop | None = None,\n        ca_certs: str | None = None,\n        certfile: str | None = None,\n        keyfile: str | None = None,\n        **kwargs: Any,\n    ) -> None:\n        """Run this application.\n\n        This is best used for development only, see Hypercorn for\n        production servers.\n\n        Arguments:\n            host: Hostname to listen on. By default this is loopback\n                only, use 0.0.0.0 to have the server listen externally.\n            port: Port number to listen on.\n            debug: If set enable (or disable) debug mode and debug output.\n            use_reloader: Automatically reload on code changes.\n            loop: Asyncio loop to create the server in, if None, take default one.\n                If specified it is the caller\'s responsibility to close and cleanup the\n                loop.\n            ca_certs: Path to the SSL CA certificate file.\n            certfile: Path to the SSL certificate file.\n            keyfile: Path to the SSL key file.\n        """\n        if kwargs:\n            warnings.warn(\n                f"Additional arguments, {\',\'.join(kwargs.keys())}, are not supported.\\n"\n                "They may be supported by Hypercorn, which is the ASGI server Quart "\n                "uses by default. This method is meant for development and debugging.",\n                stacklevel=2,\n            )\n\n        if loop is None:\n            loop = asyncio.new_event_loop()\n            asyncio.set_event_loop(loop)\n\n        if "QUART_DEBUG" in os.environ:\n            self.debug = get_debug_flag()\n\n        if debug is not None:\n            self.debug = debug\n\n        loop.set_debug(self.debug)\n\n        shutdown_event = asyncio.Event()\n\n        def _signal_handler(*_: Any) -> None:\n            shutdown_event.set()\n\n        for signal_name in {"SIGINT", "SIGTERM", "SIGBREAK"}:\n            if hasattr(signal, signal_name):\n                try:\n                    loop.add_signal_handler(getattr(signal, signal_name), _signal_handler)\n                except NotImplementedError:\n                    # Add signal handler may not be implemented on Windows\n                    signal.signal(getattr(signal, signal_name), _signal_handler)\n\n        server_name = self.config.get("SERVER_NAME")\n        sn_host = None\n        sn_port = None\n        if server_name is not None:\n            sn_host, _, sn_port = server_name.partition(":")\n\n        if host is None:\n            host = sn_host or "127.0.0.1"\n\n        if port is None:\n            port = int(sn_port or "5000")\n\n        task = self.run_task(\n            host,\n            port,\n            debug,\n            ca_certs,\n            certfile,\n            keyfile,\n            shutdown_trigger=shutdown_event.wait,  # type: ignore\n        )\n        print(f" * Serving Quart app \'{self.name}\'")  # noqa: T201\n        print(f" * Debug mode: {self.debug or False}")  # noqa: T201\n        print(" * Please use an ASGI server (e.g. Hypercorn) directly in production")  # noqa: T201\n        scheme = "https" if certfile is not None and keyfile is not None else "http"\n        print(f" * Running on {scheme}://{host}:{port} (CTRL + C to quit)")  # noqa: T201\n\n        tasks = [loop.create_task(task)]\n\n        if use_reloader:\n            tasks.append(loop.create_task(observe_changes(asyncio.sleep, shutdown_event)))\n\n        reload_ = False\n        try:\n            loop.run_until_complete(asyncio.gather(*tasks))\n        except MustReloadError:\n            reload_ = True\n        finally:\n            try:\n                _cancel_all_tasks(loop)\n                loop.run_until_complete(loop.shutdown_asyncgens())\n            finally:\n                asyncio.set_event_loop(None)\n                loop.close()\n\n        if reload_:\n            restart()\n\n    def run_task(\n        self,\n        host: str = "127.0.0.1",\n        port: int = 5000,\n        debug: bool | None = None,\n        ca_certs: str | None = None,\n        certfile: str | None = None,\n        keyfile: str | None = None,\n        shutdown_trigger: Callable[..., Awaitable[None]] | None = None,\n    ) -> Coroutine[None, None, None]:\n        """Return a task that when awaited runs this application.\n\n        This is best used for development only, see Hypercorn for\n        production servers.\n\n        Arguments:\n            host: Hostname to listen on. By default this is loopback\n                only, use 0.0.0.0 to have the server listen externally.\n            port: Port number to listen on.\n            debug: If set enable (or disable) debug mode and debug output.\n            ca_certs: Path to the SSL CA certificate file.\n            certfile: Path to the SSL certificate file.\n            keyfile: Path to the SSL key file.\n\n        """\n        config = HyperConfig()\n        config.access_log_format = "%(h)s %(r)s %(s)s %(b)s %(D)s"\n        config.accesslog = "-"\n        config.bind = [f"{host}:{port}"]\n        config.ca_certs = ca_certs\n        config.certfile = certfile\n        if debug is not None:\n            self.debug = debug\n        config.errorlog = config.accesslog\n        config.keyfile = keyfile\n\n        return serve(self, config, shutdown_trigger=shutdown_trigger)\n\n    def test_client(self, use_cookies: bool = True, **kwargs: Any) -> TestClientProtocol:\n        """Creates and returns a test client."""\n        return self.test_client_class(self, use_cookies=use_cookies, **kwargs)\n\n    def test_cli_runner(self, **kwargs: Any) -> QuartCliRunner:\n        """Creates and returns a CLI test runner."""\n        return self.test_cli_runner_class(self, **kwargs)  # type: ignore\n\n    @setupmethod\n    def before_websocket(\n        self,\n        func: T_before_websocket,\n    ) -> T_before_websocket:\n        """Add a before websocket function.\n\n        This is designed to be used as a decorator, if used to\n        decorate a synchronous function, the function will be wrapped\n        in :func:`~quart.utils.run_sync` and run in a thread executor\n        (with the wrapped function returned). An example usage,\n\n        .. code-block:: python\n\n            @app.before_websocket\n            async def func():\n                ...\n\n        Arguments:\n            func: The before websocket function itself.\n        """\n        self.before_websocket_funcs[None].append(func)\n        return func\n\n    @setupmethod\n    def after_websocket(\n        self,\n        func: T_after_websocket,\n    ) -> T_after_websocket:\n        """Add an after websocket function.\n\n        This is designed to be used as a decorator, if used to\n        decorate a synchronous function, the function will be wrapped\n        in :func:`~quart.utils.run_sync` and run in a thread executor\n        (with the wrapped function returned). An example usage,\n\n        .. code-block:: python\n\n            @app.after_websocket\n            async def func(response):\n                return response\n\n        Arguments:\n            func: The after websocket function itself.\n        """\n        self.after_websocket_funcs[None].append(func)\n        return func\n\n    @setupmethod\n    def teardown_websocket(\n        self,\n        func: T_teardown,\n    ) -> T_teardown:\n        """Add a teardown websocket function.\n        This is designed to be used as a decorator, if used to\n        decorate a synchronous function, the function will be wrapped\n        in :func:`~quart.utils.run_sync` and run in a thread executor\n        (with the wrapped function returned). An example usage,\n        .. code-block:: python\n            @app.teardown_websocket\n            async def func():\n                ...\n        Arguments:\n            func: The teardown websocket function itself.\n        """\n        self.teardown_websocket_funcs[None].append(func)\n        return func\n\n    async def handle_http_exception(\n        self, error: HTTPException\n    ) -> HTTPException | ResponseReturnValue:\n        """Handle a HTTPException subclass error.\n\n        This will attempt to find a handler for the error and if fails\n        will fall back to the error response.\n        """\n        if error.code is None:\n            return error\n\n        if isinstance(error, RoutingException):\n            return error\n\n        blueprints = []\n        if has_request_context():\n            blueprints = request.blueprints\n        elif has_websocket_context():\n            blueprints = websocket.blueprints\n\n        handler = self._find_error_handler(error, blueprints)\n        if handler is None:\n            return error\n        else:\n            return await self.ensure_async(handler)(error)  # type: ignore\n\n    async def handle_user_exception(self, error: Exception) -> HTTPException | ResponseReturnValue:\n        """Handle an exception that has been raised.\n\n        This should forward :class:`~quart.exception.HTTPException` to\n        :meth:`handle_http_exception`, then attempt to handle the\n        error. If it cannot it should reraise the error.\n        """\n        if isinstance(error, BadRequestKeyError) and (\n            self.debug or self.config["TRAP_BAD_REQUEST_ERRORS"]\n        ):\n            error.show_exception = True\n\n        if isinstance(error, HTTPException) and not self.trap_http_exception(error):\n            return await self.handle_http_exception(error)\n\n        blueprints = []\n        if has_request_context():\n            blueprints = request.blueprints\n        elif has_websocket_context():\n            blueprints = websocket.blueprints\n\n        handler = self._find_error_handler(error, blueprints)\n        if handler is None:\n            raise error\n        return await self.ensure_async(handler)(error)  # type: ignore\n\n    async def handle_exception(self, error: Exception) -> ResponseTypes:\n        """Handle an uncaught exception.\n\n        By default this switches the error response to a 500 internal\n        server error.\n        """\n        exc_info = sys.exc_info()\n        await got_request_exception.send_async(\n            self, _sync_wrapper=self.ensure_async, exception=error  # type: ignore\n        )\n        propagate = self.config["PROPAGATE_EXCEPTIONS"]\n\n        if propagate is None:\n            propagate = self.testing or self.debug\n\n        if propagate:\n            # Re-raise if called with an active exception, otherwise\n            # raise the passed in exception.\n            if exc_info[1] is error:\n                raise\n\n            raise error\n\n        self.log_exception(exc_info)\n        server_error: InternalServerError | ResponseReturnValue\n        server_error = InternalServerError(original_exception=error)\n        handler = self._find_error_handler(server_error, request.blueprints)\n\n        if handler is not None:\n            server_error = await self.ensure_async(handler)(server_error)  # type: ignore\n\n        return await self.finalize_request(server_error, from_error_handler=True)\n\n    async def handle_websocket_exception(self, error: Exception) -> ResponseTypes | None:\n        """Handle an uncaught exception.\n\n        By default this logs the exception and then re-raises it.\n        """\n        exc_info = sys.exc_info()\n        await got_websocket_exception.send_async(\n            self, _sync_wrapper=self.ensure_async, exception=error  # type: ignore\n        )\n        propagate = self.config["PROPAGATE_EXCEPTIONS"]\n\n        if propagate is None:\n            propagate = self.testing or self.debug\n\n        if propagate:\n            # Re-raise if called with an active exception, otherwise\n            # raise the passed in exception.\n            if exc_info[1] is error:\n                raise\n\n            raise error\n\n        self.log_exception(exc_info)\n        server_error: InternalServerError | ResponseReturnValue\n        server_error = InternalServerError(original_exception=error)\n        handler = self._find_error_handler(server_error, websocket.blueprints)\n\n        if handler is not None:\n            server_error = await self.ensure_async(handler)(server_error)  # type: ignore\n\n        return await self.finalize_websocket(server_error, from_error_handler=True)\n\n    def log_exception(\n        self,\n        exception_info: tuple[type, BaseException, TracebackType] | tuple[None, None, None],\n    ) -> None:\n        """Log a exception to the :attr:`logger`.\n\n        By default this is only invoked for unhandled exceptions.\n        """\n        if has_request_context():\n            request_ = request_ctx.request\n            self.logger.error(\n                f"Exception on request {request_.method} {request_.path}", exc_info=exception_info\n            )\n        elif has_websocket_context():\n            websocket_ = websocket_ctx.websocket\n            self.logger.error(f"Exception on websocket {websocket_.path}", exc_info=exception_info)\n        else:\n            self.logger.error("Exception", exc_info=exception_info)\n\n    @overload\n    def ensure_async(self, func: Callable[P, Awaitable[T]]) -> Callable[P, Awaitable[T]]: ...\n\n    @overload\n    def ensure_async(self, func: Callable[P, T]) -> Callable[P, Awaitable[T]]: ...\n\n    def ensure_async(\n        self, func: Union[Callable[P, Awaitable[T]], Callable[P, T]]\n    ) -> Callable[P, Awaitable[T]]:\n        """Ensure that the returned func is async and calls the func.\n\n        .. versionadded:: 0.11\n\n        Override if you wish to change how synchronous functions are\n        run. Before Quart 0.11 this did not run the synchronous code\n        in an executor.\n        """\n        if iscoroutinefunction(func):\n            return func\n        else:\n            return self.sync_to_async(cast(Callable[P, T], func))\n\n    def sync_to_async(self, func: Callable[P, T]) -> Callable[P, Awaitable[T]]:\n        """Return a async function that will run the synchronous function *func*.\n\n        This can be used as so,::\n\n            result = await app.sync_to_async(func)(*args, **kwargs)\n\n        Override this method to change how the app converts sync code\n        to be asynchronously callable.\n        """\n        return run_sync(func)\n\n    async def do_teardown_request(\n        self, exc: BaseException | None, request_context: RequestContext | None = None\n    ) -> None:\n        """Teardown the request, calling the teardown functions.\n\n        Arguments:\n            exc: Any exception not handled that has caused the request\n                to teardown.\n            request_context: The request context, optional as Flask\n                omits this argument.\n        """\n        names = [*(request_context or request_ctx).request.blueprints, None]\n        for name in names:\n            for function in reversed(self.teardown_request_funcs[name]):\n                await self.ensure_async(function)(exc)\n\n        await request_tearing_down.send_async(\n            self, _sync_wrapper=self.ensure_async, exc=exc  # type: ignore\n        )\n\n    async def do_teardown_websocket(\n        self, exc: BaseException | None, websocket_context: WebsocketContext | None = None\n    ) -> None:\n        """Teardown the websocket, calling the teardown functions.\n\n        Arguments:\n            exc: Any exception not handled that has caused the websocket\n                to teardown.\n            websocket_context: The websocket context, optional as Flask\n                omits this argument.\n        """\n        names = [*(websocket_context or websocket_ctx).websocket.blueprints, None]\n        for name in names:\n            for function in reversed(self.teardown_websocket_funcs[name]):\n                await self.ensure_async(function)(exc)\n\n        await websocket_tearing_down.send_async(\n            self, _sync_wrapper=self.ensure_async, exc=exc  # type: ignore\n        )\n\n    async def do_teardown_appcontext(self, exc: BaseException | None) -> None:\n        """Teardown the app (context), calling the teardown functions."""\n        for function in self.teardown_appcontext_funcs:\n            await self.ensure_async(function)(exc)\n        await appcontext_tearing_down.send_async(\n            self, _sync_wrapper=self.ensure_async, exc=exc  # type: ignore\n        )\n\n    def app_context(self) -> AppContext:\n        """Create and return an app context.\n\n        This is best used within a context, i.e.\n\n        .. code-block:: python\n\n            async with app.app_context():\n                ...\n        """\n        return AppContext(self)\n\n    def request_context(self, request: Request) -> RequestContext:\n        """Create and return a request context.\n\n        Use the :meth:`test_request_context` whilst testing. This is\n        best used within a context, i.e.\n\n        .. code-block:: python\n\n            async with app.request_context(request):\n                ...\n\n        Arguments:\n            request: A request to build a context around.\n        """\n        return RequestContext(self, request)\n\n    def websocket_context(self, websocket: Websocket) -> WebsocketContext:\n        """Create and return a websocket context.\n\n        Use the :meth:`test_websocket_context` whilst testing. This is\n        best used within a context, i.e.\n\n        .. code-block:: python\n\n            async with app.websocket_context(websocket):\n                ...\n\n        Arguments:\n            websocket: A websocket to build a context around.\n        """\n        return WebsocketContext(self, websocket)\n\n    def test_app(self) -> TestAppProtocol:\n        return self.test_app_class(self)\n\n    def test_request_context(\n        self,\n        path: str,\n        *,\n        method: str = "GET",\n        headers: dict | Headers | None = None,\n        query_string: dict | None = None,\n        scheme: str = "http",\n        send_push_promise: Callable[[str, Headers], Awaitable[None]] = no_op_push,\n        data: AnyStr | None = None,\n        form: dict | None = None,\n        json: Any = sentinel,\n        root_path: str = "",\n        http_version: str = "1.1",\n        scope_base: dict | None = None,\n        auth: Authorization | tuple[str, str] | None = None,\n        subdomain: str | None = None,\n    ) -> RequestContext:\n        """Create a request context for testing purposes.\n\n        This is best used for testing code within request contexts. It\n        is a simplified wrapper of :meth:`request_context`. It is best\n        used in a with block, i.e.\n\n        .. code-block:: python\n\n            async with app.test_request_context("/", method="GET"):\n                ...\n\n        Arguments:\n            path: Request path.\n            method: HTTP verb\n            headers: Headers to include in the request.\n            query_string: To send as a dictionary, alternatively the\n                query_string can be determined from the path.\n            scheme: Scheme for the request, default http.\n        """\n        headers, path, query_string_bytes = make_test_headers_path_and_query_string(\n            self,\n            path,\n            headers,\n            query_string,\n            auth,\n            subdomain,\n        )\n        request_body, body_headers = make_test_body_with_headers(data=data, form=form, json=json)\n        headers.update(**body_headers)\n        scope = make_test_scope(\n            "http",\n            path,\n            method,\n            headers,\n            query_string_bytes,\n            scheme,\n            root_path,\n            http_version,\n            scope_base,\n        )\n        request = self.request_class(\n            method,\n            scheme,\n            path,\n            query_string_bytes,\n            headers,\n            root_path,\n            http_version,\n            send_push_promise=send_push_promise,\n            scope=scope,\n        )\n        request.body.set_result(request_body)\n        return self.request_context(request)\n\n    def add_background_task(self, func: Callable, *args: Any, **kwargs: Any) -> None:\n        async def _wrapper() -> None:\n            try:\n                async with self.app_context():\n                    await self.ensure_async(func)(*args, **kwargs)\n            except Exception as error:\n                await self.handle_background_exception(error)\n\n        task = asyncio.get_event_loop().create_task(_wrapper())\n        self.background_tasks.add(task)\n        task.add_done_callback(self.background_tasks.discard)\n\n    async def handle_background_exception(self, error: Exception) -> None:\n        await got_background_exception.send_async(\n            self, _sync_wrapper=self.ensure_async, exception=error  # type: ignore\n        )\n\n        self.log_exception(sys.exc_info())\n\n    async def make_default_options_response(self) -> Response:\n        """This is the default route function for OPTIONS requests."""\n        methods = request_ctx.url_adapter.allowed_methods()\n        return self.response_class("", headers={"Allow": ", ".join(methods)})\n\n    async def make_response(self, result: ResponseReturnValue | HTTPException) -> ResponseTypes:\n        """Make a Response from the result of the route handler.\n\n        The result itself can either be:\n          - A Response object (or subclass).\n          - A tuple of a ResponseValue and a header dictionary.\n          - A tuple of a ResponseValue, status code and a header dictionary.\n\n        A ResponseValue is either a Response object (or subclass) or a str.\n        """\n        headers: HeadersValue | None = None\n        status: StatusCode | None = None\n        if isinstance(result, tuple):\n            if len(result) == 3:\n                value, status, headers = result\n            elif len(result) == 2:\n                value, status_or_headers = result\n\n                if isinstance(status_or_headers, (Headers, dict, list)):\n                    headers = status_or_headers\n                    status = None\n                elif status_or_headers is not None:\n                    status = status_or_headers  # type: ignore[assignment]\n            else:\n                raise TypeError(\n                    """The response value returned must be either (body, status), (body,\n                    headers), or (body, status, headers)"""\n                )\n        else:\n            value = result  # type: ignore[assignment]\n\n        if value is None:\n            raise TypeError("The response value returned by the view function cannot be None")\n\n        response: ResponseTypes\n        if isinstance(value, HTTPException):\n            response = value.get_response()  # type: ignore\n        elif not isinstance(value, (Response, WerkzeugResponse)):\n            if (\n                isinstance(value, (str, bytes, bytearray))\n                or isgenerator(value)\n                or isasyncgen(value)\n            ):\n                response = self.response_class(value)\n            elif isinstance(value, (list, dict)):\n                response = self.json.response(value)  # type: ignore[assignment]\n            else:\n                raise TypeError(f"The response value type ({type(value).__name__}) is not valid")\n        else:\n            response = value\n\n        if status is not None:\n            response.status_code = int(status)\n\n        if headers is not None:\n            response.headers.update(headers)\n\n        return response\n\n    async def handle_request(self, request: Request) -> ResponseTypes:\n        async with self.request_context(request) as request_context:\n            try:\n                return await self.full_dispatch_request(request_context)\n            except asyncio.CancelledError:\n                raise  # CancelledErrors should be handled by serving code.\n            except Exception as error:\n                return await self.handle_exception(error)\n            finally:\n                if request.scope.get("_quart._preserve_context", False):\n                    self._preserved_context = request_context.copy()\n\n    async def handle_websocket(self, websocket: Websocket) -> ResponseTypes | None:\n        async with self.websocket_context(websocket) as websocket_context:\n            try:\n                return await self.full_dispatch_websocket(websocket_context)\n            except asyncio.CancelledError:\n                raise  # CancelledErrors should be handled by serving code.\n            except Exception as error:\n                return await self.handle_websocket_exception(error)\n            finally:\n                if websocket.scope.get("_quart._preserve_context", False):\n                    self._preserved_context = websocket_context.copy()\n\n    async def full_dispatch_request(\n        self, request_context: RequestContext | None = None\n    ) -> ResponseTypes:\n        """Adds pre and post processing to the request dispatching.\n\n        Arguments:\n            request_context: The request context, optional as Flask\n                omits this argument.\n        """\n        try:\n            await request_started.send_async(self, _sync_wrapper=self.ensure_async)  # type: ignore\n\n            result: ResponseReturnValue | HTTPException | None\n            result = await self.preprocess_request(request_context)\n            if result is None:\n                result = await self.dispatch_request(request_context)\n        except Exception as error:\n            result = await self.handle_user_exception(error)\n        return await self.finalize_request(result, request_context)\n\n    async def full_dispatch_websocket(\n        self, websocket_context: WebsocketContext | None = None\n    ) -> ResponseTypes | None:\n        """Adds pre and post processing to the websocket dispatching.\n\n        Arguments:\n            websocket_context: The websocket context, optional to match\n                the Flask convention.\n        """\n        try:\n            await websocket_started.send_async(\n                self, _sync_wrapper=self.ensure_async  # type: ignore\n            )\n\n            result: ResponseReturnValue | HTTPException | None\n            result = await self.preprocess_websocket(websocket_context)\n            if result is None:\n                result = await self.dispatch_websocket(websocket_context)\n        except Exception as error:\n            result = await self.handle_user_exception(error)\n        return await self.finalize_websocket(result, websocket_context)\n\n    async def preprocess_request(\n        self, request_context: RequestContext | None = None\n    ) -> ResponseReturnValue | None:\n        """Preprocess the request i.e. call before_request functions.\n\n        Arguments:\n            request_context: The request context, optional as Flask\n                omits this argument.\n        """\n        names = [None, *reversed((request_context or request_ctx).request.blueprints)]\n\n        for name in names:\n            for processor in self.url_value_preprocessors[name]:\n                processor(request.endpoint, request.view_args)\n\n        for name in names:\n            for function in self.before_request_funcs[name]:\n                result = await self.ensure_async(function)()\n                if result is not None:\n                    return result  # type: ignore\n\n        return None\n\n    async def preprocess_websocket(\n        self, websocket_context: WebsocketContext | None = None\n    ) -> ResponseReturnValue | None:\n        """Preprocess the websocket i.e. call before_websocket functions.\n\n        Arguments:\n            websocket_context: The websocket context, optional as Flask\n                omits this argument.\n        """\n        names = [\n            None,\n            *reversed((websocket_context or websocket_ctx).websocket.blueprints),\n        ]\n\n        for name in names:\n            for processor in self.url_value_preprocessors[name]:\n                processor(request.endpoint, request.view_args)\n\n        for name in names:\n            for function in self.before_websocket_funcs[name]:\n                result = await self.ensure_async(function)()\n                if result is not None:\n                    return result  # type: ignore\n\n        return None\n\n    def raise_routing_exception(self, request: BaseRequestWebsocket) -> NoReturn:\n        raise request.routing_exception\n\n    async def dispatch_request(\n        self, request_context: RequestContext | None = None\n    ) -> ResponseReturnValue:\n        """Dispatch the request to the view function.\n\n        Arguments:\n            request_context: The request context, optional as Flask\n                omits this argument.\n        """\n        request_ = (request_context or request_ctx).request\n        if request_.routing_exception is not None:\n            self.raise_routing_exception(request_)\n\n        if request_.method == "OPTIONS" and request_.url_rule.provide_automatic_options:\n            return await self.make_default_options_response()\n\n        handler = self.view_functions[request_.url_rule.endpoint]\n        return await self.ensure_async(handler)(**request_.view_args)  # type: ignore\n\n    async def dispatch_websocket(\n        self, websocket_context: WebsocketContext | None = None\n    ) -> ResponseReturnValue | None:\n        """Dispatch the websocket to the view function.\n\n        Arguments:\n            websocket_context: The websocket context, optional to match\n                the Flask convention.\n        """\n        websocket_ = (websocket_context or websocket_ctx).websocket\n        if websocket_.routing_exception is not None:\n            self.raise_routing_exception(websocket_)\n\n        handler = self.view_functions[websocket_.url_rule.endpoint]\n        return await self.ensure_async(handler)(**websocket_.view_args)  # type: ignore\n\n    async def finalize_request(\n        self,\n        result: ResponseReturnValue | HTTPException,\n        request_context: RequestContext | None = None,\n        from_error_handler: bool = False,\n    ) -> ResponseTypes:\n        """Turns the view response return value into a response.\n\n        Arguments:\n            result: The result of the request to finalize into a response.\n            request_context: The request context, optional as Flask\n                omits this argument.\n        """\n        response = await self.make_response(result)\n        try:\n            response = await self.process_response(response, request_context)\n            await request_finished.send_async(\n                self, _sync_wrapper=self.ensure_async, response=response  # type: ignore\n            )\n        except Exception:\n            if not from_error_handler:\n                raise\n            self.logger.exception("Request finalizing errored")\n        return response\n\n    async def finalize_websocket(\n        self,\n        result: ResponseReturnValue | HTTPException,\n        websocket_context: WebsocketContext | None = None,\n        from_error_handler: bool = False,\n    ) -> ResponseTypes | None:\n        """Turns the view response return value into a response.\n\n        Arguments:\n            result: The result of the websocket to finalize into a response.\n            websocket_context: The websocket context, optional as Flask\n                omits this argument.\n        """\n        if result is not None:\n            response = await self.make_response(result)\n        else:\n            response = None\n        try:\n            response = await self.postprocess_websocket(response, websocket_context)\n            await websocket_finished.send_async(\n                self, _sync_wrapper=self.ensure_async, response=response  # type: ignore\n            )\n        except Exception:\n            if not from_error_handler:\n                raise\n            self.logger.exception("Request finalizing errored")\n        return response\n\n    async def process_response(\n        self,\n        response: ResponseTypes,\n        request_context: RequestContext | None = None,\n    ) -> ResponseTypes:\n        """Postprocess the request acting on the response.\n\n        Arguments:\n            response: The response after the request is finalized.\n            request_context: The request context, optional as Flask\n                omits this argument.\n        """\n        names = [*(request_context or request_ctx).request.blueprints, None]\n\n        for function in (request_context or request_ctx)._after_request_functions:\n            response = await self.ensure_async(function)(response)  # type: ignore\n\n        for name in names:\n            for function in reversed(self.after_request_funcs[name]):\n                response = await self.ensure_async(function)(response)\n\n        session_ = (request_context or request_ctx).session\n        if not self.session_interface.is_null_session(session_):\n            await self.ensure_async(self.session_interface.save_session)(self, session_, response)\n        return response\n\n    async def postprocess_websocket(\n        self,\n        response: ResponseTypes | None,\n        websocket_context: WebsocketContext | None = None,\n    ) -> ResponseTypes:\n        """Postprocess the websocket acting on the response.\n\n        Arguments:\n            response: The response after the websocket is finalized.\n            websocket_context: The websocket context, optional as Flask\n                omits this argument.\n        """\n        names = [*(websocket_context or websocket_ctx).websocket.blueprints, None]\n\n        for function in (websocket_context or websocket_ctx)._after_websocket_functions:\n            response = await self.ensure_async(function)(response)  # type: ignore\n\n        for name in names:\n            for function in reversed(self.after_websocket_funcs[name]):\n                response = await self.ensure_async(function)(response)  # type: ignore\n\n        session_ = (websocket_context or websocket_ctx).session\n        if not self.session_interface.is_null_session(session_):\n            await self.session_interface.save_session(self, session_, response)\n        return response\n\n    async def __call__(\n        self, scope: Scope, receive: ASGIReceiveCallable, send: ASGISendCallable\n    ) -> None:\n        """Called by ASGI servers.\n\n        The related :meth:`~quart.app.Quart.asgi_app` is called,\n        allowing for middleware usage whilst keeping the top level app\n        a :class:`~quart.app.Quart` instance.\n        """\n        await self.asgi_app(scope, receive, send)\n\n    async def asgi_app(\n        self, scope: Scope, receive: ASGIReceiveCallable, send: ASGISendCallable\n    ) -> None:\n        """This handles ASGI calls, it can be wrapped in middleware.\n\n        When using middleware with Quart it is preferable to wrap this\n        method rather than the app itself. This is to ensure that the\n        app is an instance of this class - which allows the quart cli\n        to work correctly. To use this feature simply do,\n\n        .. code-block:: python\n\n            app.asgi_app = middleware(app.asgi_app)\n\n        """\n        asgi_handler: ASGIHTTPProtocol | ASGILifespanProtocol | ASGIWebsocketProtocol\n        if scope["type"] == "http":\n            asgi_handler = self.asgi_http_class(self, scope)\n        elif scope["type"] == "websocket":\n            asgi_handler = self.asgi_websocket_class(self, scope)\n        elif scope["type"] == "lifespan":\n            asgi_handler = self.asgi_lifespan_class(self, scope)\n        else:\n            raise RuntimeError("ASGI Scope type is unknown")\n        await asgi_handler(receive, send)\n\n    async def startup(self) -> None:\n        self.shutdown_event = self.event_class()\n        try:\n            async with self.app_context():\n                for func in self.before_serving_funcs:\n                    await self.ensure_async(func)()\n                for gen in self.while_serving_gens:\n                    await gen.__anext__()\n        except Exception as error:\n            await got_serving_exception.send_async(\n                self, _sync_wrapper=self.ensure_async, exception=error  # type: ignore\n            )\n            self.log_exception(sys.exc_info())\n            raise\n\n    async def shutdown(self) -> None:\n        self.shutdown_event.set()\n        try:\n            await asyncio.wait_for(\n                asyncio.gather(*self.background_tasks),\n                timeout=self.config["BACKGROUND_TASK_SHUTDOWN_TIMEOUT"],\n            )\n        except asyncio.TimeoutError:\n            await cancel_tasks(self.background_tasks)\n\n        try:\n            async with self.app_context():\n                for func in self.after_serving_funcs:\n                    await self.ensure_async(func)()\n                for gen in self.while_serving_gens:\n                    try:\n                        await gen.__anext__()\n                    except StopAsyncIteration:\n                        pass\n                    else:\n                        raise RuntimeError("While serving generator didn\'t terminate")\n        except Exception as error:\n            await got_serving_exception.send_async(\n                self, _sync_wrapper=self.ensure_async, exception=error  # type: ignore\n            )\n            self.log_exception(sys.exc_info())\n            raise\n\n\ndef _cancel_all_tasks(loop: asyncio.AbstractEventLoop) -> None:\n    tasks = [task for task in asyncio.all_tasks(loop) if not task.done()]\n    if not tasks:\n        return\n\n    for task in tasks:\n        task.cancel()\n    loop.run_until_complete(asyncio.gather(*tasks, return_exceptions=True))\n\n    for task in tasks:\n        if not task.cancelled() and task.exception() is not None:\n            loop.call_exception_handler(\n                {\n                    "message": "unhandled exception during shutdown",\n                    "exception": task.exception(),\n                    "task": task,\n                }\n            )\n',
        }
